create table if not exists public.history (id uuid primary key default gen_random_uuid(), household_id uuid not null references public.households(id) on delete cascade, item_id uuid references public.items(id), actor_id uuid not null references auth.users(id), action text not null, from_location_id uuid, to_location_id uuid, changed_fields jsonb not null default '{}'::jsonb, device_id text not null, occurred_at timestamptz not null default now());
create table if not exists public.sync_ops (id uuid primary key, household_id uuid not null references public.households(id) on delete cascade, actor_id uuid not null references auth.users(id), device_id text not null, op_type text not null, entity_type text not null, entity_id uuid not null, base_version integer, payload jsonb not null, status text not null check(status in ('pending','pushing','synced','failed','conflicted')), retry_count integer not null default 0, last_error text, created_at timestamptz not null, updated_at timestamptz not null, synced_at timestamptz);
create table if not exists public.device_sync (id uuid primary key default gen_random_uuid(), household_id uuid not null references public.households(id) on delete cascade, user_id uuid not null references auth.users(id), device_id text not null, last_pulled_cursor text, last_pushed_at timestamptz, created_at timestamptz not null default now(), updated_at timestamptz not null default now(), unique(household_id, user_id, device_id));
create table if not exists public.conflicts (id uuid primary key default gen_random_uuid(), household_id uuid not null references public.households(id) on delete cascade, sync_op_id uuid not null, entity_type text not null, entity_id uuid not null, local_payload jsonb not null, remote_payload jsonb not null, created_at timestamptz not null default now(), updated_at timestamptz not null default now(), resolved_at timestamptz);
create table if not exists public.backup_snapshots (id uuid primary key default gen_random_uuid(), household_id uuid not null references public.households(id) on delete cascade, created_by uuid not null references auth.users(id), manifest jsonb not null, storage_key text, created_at timestamptz not null default now());
create index if not exists history_household_time_idx on public.history(household_id, occurred_at); create index if not exists sync_ops_household_status_idx on public.sync_ops(household_id, status, created_at);
